import React, { useEffect, useState } from 'react';
import { useParams } from 'react-router-dom';
import { ethers } from 'ethers';
import AgriChainArtifact from '../artifacts/AgriChain.json';
import './Trace.css';

// Ensure to replace this with the actual deployed address or import it from a config file
const CONTRACT_ADDRESS = process.env.REACT_APP_CONTRACT_ADDRESS || "0xYourDeployedContractAddressHere";

const ROLES = ["None", "Admin", "Farmer", "Distributor", "Inspector", "Retailer"];

const Trace = () => {
  const { id } = useParams();
  const [batch, setBatch] = useState(null);
  const [events, setEvents] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  useEffect(() => {
    const fetchBatchData = async () => {
      try {
        setLoading(true);
        // Connect to local Ganache network for read-only access (consumer view)
        const provider = new ethers.JsonRpcProvider("http://127.0.0.1:7545");
        const contract = new ethers.Contract(CONTRACT_ADDRESS, AgriChainArtifact.abi, provider);

        // 1. Fetch current batch state
        const batchData = await contract.getBatch(id);

        // Batch object structure based on Solidity struct
        if (Number(batchData.id) === 0) {
          setError("Batch not found on the blockchain.");
          setLoading(false);
          return;
        }

        setBatch({
          id: Number(batchData.id),
          cropType: batchData.cropType,
          currentOwner: batchData.currentOwner,
          location: batchData.location,
          timestamp: Number(batchData.timestamp),
          isQualityVerified: batchData.isQualityVerified,
          ownerRole: ROLES[Number(batchData.ownerRole)]
        });

        // 2. Fetch StatusUpdated events to build the timeline
        const filter = contract.filters.StatusUpdated(Number(id));
        const logs = await contract.queryFilter(filter, 0, "latest");

        const decodedEvents = logs.map(log => {
          return {
            handlerRole: ROLES[Number(log.args[1])],
            location: log.args[2],
            timestamp: Number(log.args[3]),
            transactionHash: log.transactionHash
          };
        });

        // Sort events chronologically
        decodedEvents.sort((a, b) => a.timestamp - b.timestamp);
        setEvents(decodedEvents);

      } catch (err) {
        console.error("Error fetching trace data:", err);
        setError("Failed to fetch traceability data. Ensure the blockchain is running and contract address is correct.");
      } finally {
        setLoading(false);
      }
    };

    if (id) {
      fetchBatchData();
    }
  }, [id]);

  const formatDate = (timestamp) => {
    return new Date(timestamp * 1000).toLocaleString('en-US', {
      year: 'numeric', month: 'short', day: 'numeric',
      hour: '2-digit', minute: '2-digit'
    });
  };

  if (loading) {
    return (
      <div className="trace-container">
        <div className="loader-container">
          <div className="loader"></div>
          <p>Verifying Blockchain Ledger...</p>
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="trace-container">
        <div className="trace-card error-card">
          <h2>Error</h2>
          <p>{error}</p>
        </div>
      </div>
    );
  }

  return (
    <div className="trace-container">
      <div className="trace-card">
        <h1 className="trace-title">Product Traceability</h1>

        <div className="summary-box">
          <div className="summary-item">
            <span className="summary-label">Batch ID</span>
            <span className="summary-value">#{batch?.id}</span>
          </div>
          <div className="summary-item">
            <span className="summary-label">Crop Type</span>
            <span className="summary-value">{batch?.cropType}</span>
          </div>
          <div className="summary-item">
            <span className="summary-label">Current Owner</span>
            <span className="summary-value" title={batch?.currentOwner}>
              {batch?.currentOwner.substring(0, 6)}...{batch?.currentOwner.substring(38)}
            </span>
          </div>
          <div className="summary-item">
            <span className="summary-label">Quality Status</span>
            {batch?.isQualityVerified ? (
              <span className="quality-badge quality-verified">✔ Verified by Inspector</span>
            ) : (
              <span className="quality-badge quality-pending">Pending Inspection</span>
            )}
          </div>
        </div>

        <h2 className="timeline-role" style={{ marginBottom: "1rem" }}>Journey Timeline</h2>

        <div className="timeline">
          {/* Origin Stage */}
          <div className="timeline-item origin">
            <div className="timeline-content">
              <div className="timeline-header">
                <span className="timeline-role">Genesis: Farm Registered</span>
                <span className="timeline-date">{formatDate(batch?.timestamp)}</span>
              </div>
              <div className="timeline-location">
                📍 {events.length > 0 ? events[0]?.location || batch?.location : batch?.location}
              </div>
            </div>
          </div>

          {/* Dynamic Event Stages */}
          {events.map((evt, index) => (
            <div className="timeline-item" key={evt.transactionHash + index}>
              <div className="timeline-content">
                <div className="timeline-header">
                  <span className="timeline-role">Handled by {evt.handlerRole}</span>
                  <span className="timeline-date">{formatDate(evt.timestamp)}</span>
                </div>
                <div className="timeline-location">
                  📍 {evt.location}
                </div>
                <div className="timeline-date" style={{ fontSize: '0.75rem', marginTop: '0.5rem' }}>
                  Tx: {evt.transactionHash.substring(0, 10)}...
                </div>
              </div>
            </div>
          ))}
        </div>

        <div style={{ marginTop: '3rem', textAlign: 'center', borderTop: '1px solid rgba(255,255,255,0.1)', paddingTop: '2rem' }}>
            <p style={{ color: '#94a3b8', fontSize: '0.9rem', marginBottom: '1rem' }}>Are you a logistics handler or inspector for this batch?</p>
            <button 
                onClick={() => window.location.href = `/update-status/${id}`}
                style={{
                  background: 'transparent',
                  color: '#3b82f6',
                  border: '1px solid #3b82f6',
                  padding: '0.6rem 1.2rem',
                  borderRadius: '8px',
                  fontWeight: 600,
                  cursor: 'pointer',
                  transition: 'background 0.2s',
                }}
                onMouseOver={(e) => e.target.style.background = 'rgba(59, 130, 246, 0.1)'}
                onMouseOut={(e) => e.target.style.background = 'transparent'}
            >
                Logistics Update Portal →
            </button>
        </div>

      </div>
    </div>
  );
};

export default Trace;
